import pytest

from src.domain.parse_core.parsers.graphql_parser import GraphqlParser
from src.infrastructure.services.validators.graphql_validator_service import GraphQLValidatorService


@pytest.fixture
def graphql_validator_service():
    return GraphQLValidatorService()


@pytest.fixture
def graphql_parser(graphql_validator_service):
    return GraphqlParser(graphql_validator_service)


@pytest.fixture
def graphql_definition():
    import base64
    b64_content = ""
    return base64.b64decode(b64_content).decode('utf-8')


def test_parse_definition(graphql_parser, graphql_definition):
    graphql_parser.load_definition(graphql_definition)
    result = graphql_parser.parse()
    assert result is not None
    assert hasattr(result, "project")
    assert hasattr(result, "graphql_schema")
    graphql_schema = result.graphql_schema
    assert hasattr(graphql_schema, "directives")
    assert hasattr(graphql_schema, "enums")
    assert hasattr(graphql_schema, "interfaces")
    assert hasattr(graphql_schema, "inputs")
    assert hasattr(graphql_schema, "types")
    assert hasattr(graphql_schema, "queries")
    assert hasattr(graphql_schema, "mutations")
